tool_use_result.originalFile:
# Test harness that validates the semantic version bumper through act.
# Runs workflow structure tests, then executes test cases via act push.

$ErrorActionPreference = 'Stop'
$scriptDir = $PSScriptRoot
$resultFile = Join-Path $scriptDir 'act-result.txt'

# Clear previous results
'' | Set-Content $resultFile

function Write-Result {
    param([string]$Text)
    $Text | Add-Content $resultFile
    Write-Host $Text
}

# --- WORKFLOW STRUCTURE TESTS ---
Write-Result "=========================================="
Write-Result "WORKFLOW STRUCTURE TESTS"
Write-Result "=========================================="

$workflowPath = Join-Path $scriptDir '.github/workflows/semantic-version-bumper.yml'

# Test: workflow file exists
if (Test-Path $workflowPath) {
    Write-Result "PASS: Workflow file exists"
} else {
    Write-Result "FAIL: Workflow file not found at $workflowPath"
    exit 1
}

# Test: parse YAML structure
$yaml = Get-Content $workflowPath -Raw
if ($yaml -match 'on:') { Write-Result "PASS: Has trigger configuration" }
else { Write-Result "FAIL: Missing trigger configuration"; exit 1 }

if ($yaml -match 'push:') { Write-Result "PASS: Has push trigger" }
else { Write-Result "FAIL: Missing push trigger"; exit 1 }

if ($yaml -match 'pull_request:') { Write-Result "PASS: Has pull_request trigger" }
else { Write-Result "FAIL: Missing pull_request trigger"; exit 1 }

if ($yaml -match 'workflow_dispatch:') { Write-Result "PASS: Has workflow_dispatch trigger" }
else { Write-Result "FAIL: Missing workflow_dispatch trigger"; exit 1 }

if ($yaml -match 'jobs:') { Write-Result "PASS: Has jobs section" }
else { Write-Result "FAIL: Missing jobs section"; exit 1 }

if ($yaml -match 'test:') { Write-Result "PASS: Has test job" }
else { Write-Result "FAIL: Missing test job"; exit 1 }

if ($yaml -match 'bump:') { Write-Result "PASS: Has bump job" }
else { Write-Result "FAIL: Missing bump job"; exit 1 }

if ($yaml -match 'shell: pwsh') { Write-Result "PASS: Uses pwsh shell" }
else { Write-Result "FAIL: Missing pwsh shell directive"; exit 1 }

if ($yaml -match 'actions/checkout@v4') { Write-Result "PASS: Uses actions/checkout@v4" }
else { Write-Result "FAIL: Missing actions/checkout@v4"; exit 1 }

if ($yaml -match 'needs: test') { Write-Result "PASS: bump job depends on test job" }
else { Write-Result "FAIL: Missing job dependency"; exit 1 }

# Test: referenced script files exist
$mainScript = Join-Path $scriptDir 'Bump-SemanticVersion.ps1'
$testScript = Join-Path $scriptDir 'Bump-SemanticVersion.Tests.ps1'
if (Test-Path $mainScript) { Write-Result "PASS: Bump-SemanticVersion.ps1 exists" }
else { Write-Result "FAIL: Bump-SemanticVersion.ps1 not found"; exit 1 }
if (Test-Path $testScript) { Write-Result "PASS: Bump-SemanticVersion.Tests.ps1 exists" }
else { Write-Result "FAIL: Bump-SemanticVersion.Tests.ps1 not found"; exit 1 }

# Test: actionlint validation
$lintResult = actionlint $workflowPath 2>&1
if ($LASTEXITCODE -eq 0) {
    Write-Result "PASS: actionlint validation passed"
} else {
    Write-Result "FAIL: actionlint validation failed: $lintResult"
    exit 1
}

Write-Result ""
Write-Result "All workflow structure tests passed."
Write-Result ""

# --- ACT INTEGRATION TESTS ---
Write-Result "=========================================="
Write-Result "ACT INTEGRATION TESTS"
Write-Result "=========================================="

# Test cases: fixture file, initial version, expected new version, expected bump type
$testCases = @(
    @{ Fixture = 'patch-commits.txt'; Version = '1.0.0'; Expected = '1.0.1'; BumpType = 'patch' },
    @{ Fixture = 'minor-commits.txt'; Version = '1.1.0'; Expected = '1.2.0'; BumpType = 'minor' },
    @{ Fixture = 'major-commits.txt'; Version = '2.3.1'; Expected = '3.0.0'; BumpType = 'major' }
)

$allPassed = $true
$caseNum = 0

foreach ($tc in $testCases) {
    $caseNum++
    Write-Result ""
    Write-Result "------------------------------------------"
    Write-Result "TEST CASE $caseNum : $($tc.Fixture) ($($tc.Version) -> $($tc.Expected))"
    Write-Result "------------------------------------------"

    # Set up VERSION file with initial version for this test case
    Set-Content -Path (Join-Path $scriptDir 'VERSION') -Value $tc.Version -NoNewline

    # Run act with the fixture environment variable
    $env:BUMP_FIXTURE = $tc.Fixture
    $actOutput = & act push --rm --env "BUMP_FIXTURE=$($tc.Fixture)" 2>&1 | Out-String
    $actExit = $LASTEXITCODE

    Write-Result "Act exit code: $actExit"
    Write-Result ""
    Write-Result "--- ACT OUTPUT START ---"
    Write-Result $actOutput
    Write-Result "--- ACT OUTPUT END ---"
    Write-Result ""

    # Assert exit code
    if ($actExit -ne 0) {
        Write-Result "FAIL: act exited with non-zero code $actExit"
        $allPassed = $false
        continue
    }
    Write-Result "PASS: act exited with code 0"

    # Assert job succeeded
    if ($actOutput -match 'Job succeeded') {
        Write-Result "PASS: Job succeeded message found"
    } else {
        Write-Result "FAIL: No 'Job succeeded' in output"
        $allPassed = $false
        continue
    }

    # Assert exact expected version in output
    if ($actOutput -match "NEW_VERSION=$($tc.Expected)") {
        Write-Result "PASS: Output contains NEW_VERSION=$($tc.Expected)"
    } else {
        Write-Result "FAIL: Expected NEW_VERSION=$($tc.Expected) not found in output"
        $allPassed = $false
    }

    # Assert bump type
    if ($actOutput -match "BUMP_TYPE=$($tc.BumpType)") {
        Write-Result "PASS: Output contains BUMP_TYPE=$($tc.BumpType)"
    } else {
        Write-Result "FAIL: Expected BUMP_TYPE=$($tc.BumpType) not found in output"
        $allPassed = $false
    }

    # Assert old version
    if ($actOutput -match "OLD_VERSION=$($tc.Version)") {
        Write-Result "PASS: Output contains OLD_VERSION=$($tc.Version)"
    } else {
        Write-Result "FAIL: Expected OLD_VERSION=$($tc.Version) not found in output"
        $allPassed = $false
    }

    # Assert changelog section present
    if ($actOutput -match '---CHANGELOG---') {
        Write-Result "PASS: Changelog section present in output"
    } else {
        Write-Result "FAIL: Changelog section missing from output"
        $allPassed = $false
    }
}

Write-Result ""
Write-Result "=========================================="
if ($allPassed) {
    Write-Result "ALL TESTS PASSED"
} else {
    Write-Result "SOME TESTS FAILED"
}
Write-Result "=========================================="

# Clean up VERSION file
Remove-Item -Path (Join-Path $scriptDir 'VERSION') -ErrorAction SilentlyContinue

if (-not $allPassed) { exit 1 }
